#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

int N;
vector<string> grid;
int ans = 0;

// Direction vectors: up, down, left, right
int dr[] = {-1, 1, 0, 0};
int dc[] = {0, 0, -1, 1};

void dfs(int r, int c, int open, int closed, vector<vector<bool>>& visited) {
    // Current cell char
    char ch = grid[r][c];
    if (ch == '(') {
        // If we already started closing, cannot add '('
        if (closed > 0) return;
        open++;
    } else { // ')'
        closed++;
        // More closing than open so far -> invalid
        if (closed > open) return;
    }

    // If we have a perfectly balanced string (open == closed)
    if (open == closed) {
        ans = max(ans, open + closed);
        // Note: we can continue from here (adding more chars would break perfect balance)
        // But we are allowed to stop early. The path must be a prefix of a valid string.
        // Actually we can continue: after balanced, next char may be '(' starting a new sequence?
        // No, because you can't have '(' after ')' in a perfectly balanced string.
        // So we return after updating answer, because any continuation would break perfect balance.
        return;
    }

    // Try moving to neighbors
    for (int d = 0; d < 4; d++) {
        int nr = r + dr[d];
        int nc = c + dc[d];
        if (nr >= 0 && nr < N && nc >= 0 && nc < N && !visited[nr][nc]) {
            visited[nr][nc] = true;
            dfs(nr, nc, open, closed, visited);
            visited[nr][nc] = false;
        }
    }
}

int main() {
    cin >> N;
    grid.resize(N);
    for (int i = 0; i < N; i++) {
        cin >> grid[i];
    }

    // The starting cell must be '(' for a perfectly balanced string
    if (grid[0][0] != '(') {
        cout << 0 << endl;
        return 0;
    }

    vector<vector<bool>> visited(N, vector<bool>(N, false));
    visited[0][0] = true;
    dfs(0, 0, 0, 0, visited);

    cout << ans << endl;
    return 0;
}
